args.sparql:
SELECT ?item ?label WHERE {
  ?item wdt:P31 wd:Q13171 .
  ?item rdfs:label ?label .
  FILTER (LANG(?label) = 'en') .
  FILTER (CONTAINS(LCASE(?label), 'spiral'))
}

SELECT ?item ?label WHERE {
  ?item rdfs:label ?label .
  FILTER (LANG(?label) = 'en') .
  FILTER (CONTAINS(LCASE(?label), 'spiral'))
  LIMIT 10
}

